VALUES
  ('dietitian-moex-07214', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關營養流行病學研究敘述，下列那一項正確？', '["相對危險率（RR；Relative risk）＝暴露組的疾病發生率÷非暴露組的疾病發生率", "相對危險率（RR；Relative risk）常用於Case-control studies", "勝算比（OR；Odds ratio）常用於Cohort studies", "當RR＝1.7時，表示非暴露組的疾病發生率比暴露組的疾病發生率增加70％"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07215', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '許多國家面臨疾病的雙重負擔，不包含下列何者？', '["同一國家內，同時存有營養不良和肥胖的情況", "同一國家內，同時面臨熱量和蛋白質不足的營養問題", "在應對傳染病和營養不良問題時，同時經歷肥胖和過重", "嬰幼兒時期營養缺乏，而隨後又食用高熱量、高脂肪的食品"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07216', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何種血液蛋白質有最長的半衰期，反映較長期的蛋白質營養狀態？', '["白蛋白（Albumin）", "前白蛋白（Prealbumin）", "運鐵蛋白（Transferrin）", "視網醇結合蛋白（Retinol-binding protein）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07217', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列有關「臺灣國小學童營養健康狀況調查2001-2002」結果之敘述，何者正確？', '["都會地方，學童過重或肥胖盛行率高", "男性學童的體重與肥胖比率，均明顯比女性學童低", "山地學童對蔬果的攝取，高於都會地區", "國小學童各年齡層蛋白質平均攝取量，未達國人膳食營養素參考攝取量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07218', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據「臺灣地區老人營養健康狀況調查1999-2000」的結果，顯示老人食物攝取符合衛生福利部（原行政院 衛生署）「每日飲食指南」的是：', '["五穀根莖類", "蔬菜類", "奶類", "水果類"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07219', 'dietitian', 'dietitian-moex-102-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據「臺灣地區老人營養健康狀況調查1999-2000」的調查結果，老年人在下列何種營養素的攝取量上達 到DRIs？', '["維生素B", "維生素E", "鎂", "鐵 6"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "d0d9dce1f2b6", "answer_pdf_sha1": "4729c852d3de", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07220', 'dietitian', 'dietitian-moex-102-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '依據2002年通過之「學校衛生法」，第23條規定高級中等以下學校，班級數在多少以上須設置營養師？', '["20班", "30班", "40班", "50班"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "3bc6ca9ee8cd", "answer_pdf_sha1": "fb31348ff164", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07221', 'dietitian', 'dietitian-moex-102-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下表為某自助餐銷售分析表，則菜單中的烤雞腿的預估份數為何？ 菜餚名稱  預估份數  實際銷售份數 未出售份數  未出售份數百分比 烤雞腿  ？  450  50  10％', '["250", "500", "750", "1000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "3bc6ca9ee8cd", "answer_pdf_sha1": "fb31348ff164", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07222', 'dietitian', 'dietitian-moex-102-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列何組食物之可食重量的蛋白質量是相同的？', '["白帶魚30公克，脫脂奶1杯", "玉米粒100公克，紅蘿蔔400公克", "玉米粒200公克，紅蘿蔔200公克", "三層肉50公克，豆腐50公克"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "3bc6ca9ee8cd", "answer_pdf_sha1": "fb31348ff164", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07223', 'dietitian', 'dietitian-moex-102-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '欲供應炒高麗菜200份，每份成品熟重50公克，已知高麗菜的廢棄率為10％，膨縮率為80％，則需準 備多少公斤高麗菜？', '["10", "12", "14", "16"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:46+00:00", "source_pdf_sha1": "3bc6ca9ee8cd", "answer_pdf_sha1": "fb31348ff164", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
